#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Fix the async-enrich RecursionError (exit-0-safe, backup+py_compile+auto-restore).
Bug: _aio_running_loop() returns _aio_running_loop() (infinite self-recursion).
Fix: return asyncio.get_running_loop(). Then restart the async workers."""
import os,sys,json,time,subprocess,shutil
F="/opt/atlas/importers/atlas_enrich_async.py"
def sh(c,t=30):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception as e: return "ERR:%s"%e
out={"kind":"fix_async","ts":int(time.time())}
try:
    src=open(F).read()
    out["func_before"]=sh("sed -n '108,120p' %s"%F)
    bak=F+".bak.%d"%int(time.time()); shutil.copy2(F,bak); out["backup"]=bak
    needle="return _aio_running_loop()"
    cnt=src.count(needle)
    out["occurrences"]=cnt
    if cnt>=1:
        src2=src.replace(needle,"return asyncio.get_running_loop()",1)
        tmp=F+".new"; open(tmp,"w").write(src2)
        chk=subprocess.run(["/opt/atlas/venv/bin/python","-m","py_compile",tmp],capture_output=True,text=True)
        out["py_compile_rc"]=chk.returncode; out["py_compile_err"]=chk.stderr.strip()[:200]
        if chk.returncode==0:
            shutil.copymode(F,tmp); os.replace(tmp,F); out["result"]="PATCHED + compiles"
        else:
            os.remove(tmp); out["result"]="REVERTED (compile failed)"
    else:
        out["result"]="needle not found (already fixed?)"
    out["func_after"]=sh("sed -n '108,120p' %s"%F)
    # restart async workers + verify
    sh("systemctl reset-failed 'atlas-enrich-async*' 2>&1")
    out["restart"]=sh("systemctl restart atlas-enrich-async@1.service atlas-enrich-async-batch@1.service 2>&1; echo rc=$?")
    time.sleep(6)
    out["state_after"]=sh("for u in atlas-enrich-async@1 atlas-enrich-async-batch@1; do echo \"$u=$(systemctl is-active $u.service 2>/dev/null)\"; done")
    out["quicktest"]=sh("set -a; [ -f /etc/atlas/db.env ] && . /etc/atlas/db.env; export ATLAS_ASYNC_LANES=8; timeout 10 /opt/atlas/venv/bin/python %s 2>&1 | tail -5"%F, t=16)
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/fix-async.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"fix_async","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
